parameters.jsCode:
// Parse AI response and prepare callback payload
const items = $input.all();
const inputData = $('Extract Inputs').first().json;

try {
  const aiOutput = items[0]?.json;
  let packJson;

  if (aiOutput?.error) {
    // AI call failed
    return [{
      json: {
        callback_url: inputData.callback_url,
        callback_secret: inputData.callback_secret,
        payload: {
          run_id: inputData.run_id,
          entity_id: inputData.entity_id,
          entity_type: inputData.entity_type,
          status: 'failed',
          error_message: `AI generation failed: ${aiOutput.error}`
        }
      }
    }];
  }

  // Try to parse the AI text response as JSON
  const text = aiOutput?.text || aiOutput?.message?.content || '';
  const jsonMatch = text.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    packJson = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback: construct minimal pack from raw text
    packJson = {
      org_summary: text.substring(0, 500),
      mission_snapshot: '',
      partnership_angles: [],
      grant_alignments: [],
      suggested_outreach_angle: '',
      risks_notes: ['AI output could not be structured automatically']
    };
  }

  return [{
    json: {
      callback_url: inputData.callback_url,
      callback_secret: inputData.callback_secret,
      payload: {
        run_id: inputData.run_id,
        entity_id: inputData.entity_id,
        entity_type: inputData.entity_type,
        status: 'completed',
        pack: packJson
      }
    }
  }];
} catch (err) {
  return [{
    json: {
      callback_url: inputData.callback_url,
      callback_secret: inputData.callback_secret,
      payload: {
        run_id: inputData.run_id,
        entity_id: inputData.entity_id,
        entity_type: inputData.entity_type,
        status: 'failed',
        error_message: `Parse error: ${err.message}`
      }
    }
  }];
}
